a.style:
display: flex;
flex-direction: row;
justify-content: space-between;
align-items: center;
background: #1A3A4A;
border: 1px solid rgba(255,255,255,0.08);
border-radius: 12px;
padding: 16px 0 16px 16px;
margin-bottom: 16px;
text-decoration: none;
position: relative;
cursor: pointer;
width: 100%;
box-sizing: border-box;

img.style:
width: 110px;
height: 100%;
min-height: 100px;
object-fit: cover;
object-position: center;
border-radius: 0 10px 10px 0;
align-self: stretch;
flex-shrink: 0;
margin-left: 12px;
opacity: 0.15;
background: linear-gradient(135deg, #1E4A6E, #0D2A40);

