body.script:
/* =========================================
   HAMBURGER MENU
   ========================================= */
document.getElementById('hamburgerBtn').addEventListener('click', function() {
  document.getElementById('header').classList.toggle('nav-open');
  const spans = this.querySelectorAll('span');
  if (document.getElementById('header').classList.contains('nav-open')) {
    spans[0].style.transform = 'rotate(45deg) translate(5px,5px)';
    spans[1].style.opacity = '0';
    spans[2].style.transform = 'rotate(-45deg) translate(5px,-5px)';
  } else {
    spans[0].style.transform = '';
    spans[1].style.opacity = '';
    spans[2].style.transform = '';
  }
});

document.querySelectorAll('#headerNav a').forEach(a => {
  a.addEventListener('click', () => {
    document.getElementById('header').classList.remove('nav-open');
    const spans = document.getElementById('hamburgerBtn').querySelectorAll('span');
    spans[0].style.transform = ''; spans[1].style.opacity = ''; spans[2].style.transform = '';
  });
});

/* =========================================
   MOBILE MEGA MENU ACCORDION
   ========================================= */
document.querySelectorAll('.nav-dropdown-trigger').forEach(trigger => {
  trigger.addEventListener('click', (e) => {
    if (window.innerWidth <= 768) {
      e.preventDefault();
      const wrapper = trigger.closest('.nav-dropdown-wrapper');
      wrapper.classList.toggle('active');
    }
  });
});

/* =========================================
   SCROLL ANIMATIONS
   ========================================= */
document.addEventListener('DOMContentLoaded', () => {
  const observer = new IntersectionObserver((entries, obs) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.classList.add('animated');
        obs.unobserve(entry.target);
      }
    });
  }, { threshold: 0.1, rootMargin: '0px 0px -10% 0px' });

  document.querySelectorAll('.scroll-animate').forEach(el => observer.observe(el));
});

/* =========================================
   SMOOTH SCROLL FOR ANCHOR LINKS
   ========================================= */
document.querySelectorAll('a[href^="#"]').forEach(a => {
  a.addEventListener('click', (e) => {
    const target = document.querySelector(a.getAttribute('href'));
    if (target) {
      e.preventDefault();
      const offset = 90;
      const top = target.getBoundingClientRect().top + window.scrollY - offset;
      window.scrollTo({ top, behavior: 'smooth' });
    }
  });
});

/* =========================================
   SCROLL SPY FOR SIDEBAR TOC
   ========================================= */
const spySections = document.querySelectorAll('.article-section');
const spyLinks = document.querySelectorAll('.sidebar-toc a');

window.addEventListener('scroll', () => {
  let currentSectionId = '';
  const offset = 180; // threshold offset from top

  spySections.forEach(section => {
    const sectionTop = section.offsetTop;
    if (window.scrollY >= sectionTop - offset) {
      currentSectionId = section.getAttribute('id');
    }
  });

  spyLinks.forEach(link => {
    link.classList.remove('active');
    if (link.getAttribute('href') === `#${currentSectionId}`) {
      link.classList.add('active');
    }
  });
});

document.addEventListener('DOMContentLoaded', function() {
  var hamburgerBtn = document.getElementById('hamburgerBtn');
  var mobileMenuDropdown = document.getElementById('mobileMenuDropdown');
  if (hamburgerBtn && mobileMenuDropdown) {
    hamburgerBtn.addEventListener('click', function() {
      mobileMenuDropdown.classList.toggle('active');
    });
  }
});
